package lecture1;

public class Assignment_Operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int x=10;
		x+=2;
		System.out.println(x);
		int p=5;
		p-=2;
		System.out.println(p);
		int n=5;
		n*=2;
		System.out.println(n);
		int l=10;
		l/=5;
		System.out.println(l);
	}

}
